// Читаем существующих жителей (208 из 25.xlsx)
const existingPath = path.join(__dirname, '..', 'public', 'data', 'residents.json');
let allResidents = [];

if (fs.existsSync(existingPath)) {
  allResidents = JSON.parse(fs.readFileSync(existingPath, 'utf-8'));
  console.log(`✅ Загружено существующих: ${allResidents.length} жителей\n`);
} else {
  console.log('⚠️  Файл residents.json не найден. Создаём новый...\n');
}

// Парсим TSV
const lines = rawData.trim().split('\n');
let newId = allResidents.length > 0 ? Math.max(...allResidents.map(r => r.id)) + 1 : 1;
let added = 0;
let skipped = 0;
let duplicates = 0;

lines.forEach((line, idx) => {
  const parts = line.split('\t');
  if (parts.length < 11) return;
  
  const [num, ls, paymentCode, fio] = parts;
  const house = parts[8]?.trim();
  const apartment = parts[10]?.trim();
  const area = parts[15]?.trim();
  
  // Пропускаем компании
  if (fio.includes('ООО') || fio.includes('"') || fio.toUpperCase().includes('СЗ')) {
    skipped++;
    return;
  }
  
  if (!fio || fio.trim().length < 3) return;
  
  // Телефон из Л/С
  const phone = '+7' + ls.padStart(10, '0').slice(-10);
  
  // Проверка дубликатов
  if (allResidents.find(r => r.phone === phone)) {
    duplicates++;
    return;
  }
  
  const code = phone.slice(-4);
  
  // Квартира/Кладовая
  let apt = '', storage = '—';
  if (apartment && apartment.toUpperCase().startsWith('К')) {
    apt = '—';
    storage = apartment.replace(/К/gi, '').trim();
  } else if (apartment) {
    apt = apartment;
    const n = parseInt(apt);
    if (!isNaN(n) && n > 0) {
      storage = Math.floor(n / 10).toString();
    }
  }
  
  allResidents.push({
    id: newId++,
    fio: fio.trim().replace(/\s+/g, ' '),
    phone,
    code,
    address: `Зеленая Долина мкр., д. ${house || '—'}`,
    apartment: apt || '—',
    storage,
    complex: 'Зелёная долина',
    balance: 0,
    licSchet: ls || '',
    area: area || ''
  });
  
  added++;
});

console.log(`✅ Добавлено новых: ${added}`);
console.log(`⚠️  Пропущено (ООО): ${skipped}`);
console.log(`⚠️  Дубликаты: ${duplicates}`);
console.log(`✅ ИТОГО жителей: ${allResidents.length}\n`);

// Сохраняем
fs.writeFileSync(existingPath, JSON.stringify(allResidents, null, 2), 'utf-8');
console.log(`✅ Файл сохранён: ${existingPath}`);
console.log(`✅ Размер: ${(fs.statSync(existingPath).size / 1024).toFixed(2)} KB\n`);

// Примеры
console.log('📱 ПРИМЕРЫ (последние 10 добавленных):\n');
allResidents.slice(-10).forEach((r, i) => {
  console.log(`${allResidents.length - 9 + i}. ${r.fio}`);
  console.log(`   Телефон: ${r.phone}, Код: ${r.code}`);
  console.log(`   Адрес: ${r.address}, Кв: ${r.apartment}, Кладовая: ${r.storage}\n`);
});

